import React, { useEffect, useRef } from 'react';
import { Gradient } from './background.js';

function GradientCanvas() {
  const gradientRef = useRef(null); // Create a ref for the gradient instance
  const animationPausedRef = useRef(false); // Create a ref for the animation pause state
  const lastFrameTimeRef = useRef(performance.now()); // Create a ref for the last frame time

  useEffect(() => {
    const gradient = new Gradient();
    gradientRef.current = gradient; // Save the gradient instance in the ref

    const animate = () => {
      if (animationPausedRef.current) return;

      const currentTime = performance.now();
      const deltaTime = currentTime - lastFrameTimeRef.current;
      lastFrameTimeRef.current = currentTime;

      // Perform animation update for the deltaTime

      // Check for lag and pause animation if lag exceeds threshold
      const MAX_LAG_THRESHOLD = 200; // Maximum lag threshold in milliseconds
      if (deltaTime > MAX_LAG_THRESHOLD) {
        pauseAnimation();
      } else {
        requestAnimationFrame(animate);
      }
    };

    animate();

    return () => {
      // Cleanup function to pause animation and clear references
      pauseAnimation();
      gradientRef.current = null;
    };
  }, []);

  const pauseAnimation = () => {
    animationPausedRef.current = true;
  };

  const playAnimation = () => {
    if (!animationPausedRef.current) return;

    animationPausedRef.current = false;
    lastFrameTimeRef.current = performance.now();
    requestAnimationFrame(animate);
  };

  return (
    <div>
      <button onClick={playAnimation}>Play Animation</button>
      <button onClick={pauseAnimation}>Pause Animation</button>
      <canvas id="gradient-canvas" data-transition-in />
    </div>
  );
}

export default GradientCanvas;
